"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[66457],{85023:e=>{e.exports=JSON.parse('{"tag":{"label":"weather","permalink":"/dst-api-webdocs/docs/tags/weather","allTagsPath":"/dst-api-webdocs/docs/tags","count":25,"items":[{"id":"game-scripts/components/acidinfusible","title":"Acidinfusible","description":"Applies and removes an acid infusion effect based on world rain state and entity rain immunity, adjusting combat stats, movement speed, and visual effects accordingly.","permalink":"/dst-api-webdocs/docs/game-scripts/components/acidinfusible"},{"id":"game-scripts/components/birdspawner","title":"Birdspawner","description":"Manages the spawning and behavior of birds in the game world, including timed spawning for players, lunar hail event responses, and dynamic environmental adjustments.","permalink":"/dst-api-webdocs/docs/game-scripts/components/birdspawner"},{"id":"game-scripts/components/caveweather","title":"Caveweather","description":"Manages weather simulation including precipitation, moisture, wetness, and associated visual/audio effects in the Cave biome.","permalink":"/dst-api-webdocs/docs/game-scripts/components/caveweather"},{"id":"game-scripts/components/dryer","title":"Dryer","description":"Manages the drying process of ingredients into preserved food products, handling timers, rain exposure, and state transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryer"},{"id":"game-scripts/components/dryingrack","title":"Dryingrack","description":"Manages drying behavior for items placed in a container, handling time-based drying, weather effects (rain/acid rain), and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryingrack"},{"id":"game-scripts/components/farming_manager","title":"Farming Manager","description":"Manages soil moisture, nutrients, and farming-related systems across the world map, including plant growth, weed spawning, and Lord Fruit Fly behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farming_manager"},{"id":"game-scripts/components/frograin","title":"Frograin","description":"Manages the spawning and lifecycle of frogs during rainy spring weather, including logic for lunar rift influence and player-specific spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/components/frograin"},{"id":"game-scripts/brains/hermitcrabbrain","title":"Hermitcrabbrain","description":"Manages the AI behavior tree for the Hermit Crab, including trading, fishing, hotspring soaking, pet feeding, tea shop navigation, and environmental adaptation (weather, day/night).","permalink":"/dst-api-webdocs/docs/game-scripts/brains/hermitcrabbrain"},{"id":"game-scripts/components/lunarhailbuildup","title":"Lunarhailbuildup","description":"Manages the lunar hail buildup mechanic for a structure, tracking accumulation and decay during lunar hail events, and handling work required to remove the buildup.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarhailbuildup"},{"id":"game-scripts/components/lunarhailmanager","title":"Lunarhailmanager","description":"Manages spawning, physics, and impact behavior of falling debris during lunar hail storms, including damage application, shelter detection, and interaction with the world topology.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarhailmanager"},{"id":"game-scripts/components/moisture","title":"Moisture","description":"Manages a character\'s moisture level, including precipitation absorption, drying rates, waterproofing modifiers, and state transitions like wet or soaked.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moisture"},{"id":"game-scripts/components/moonstormlightningmanager","title":"Moonstormlightningmanager","description":"Manages periodic ground lightning spawns during moonstorms based on player proximity and network node data.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonstormlightningmanager"},{"id":"game-scripts/components/moonstormwatcher","title":"Moonstormwatcher","description":"Manages moonstorm-related speed penalties for entities based on storm intensity and vision state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/moonstormwatcher"},{"id":"game-scripts/components/raindome","title":"Raindome","description":"Manages a dynamic rain-shield dome entity that grants rain immunity to nearby entities within its active radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/raindome"},{"id":"game-scripts/components/raindomewatcher","title":"Raindomewatcher","description":"Tracks whether an entity is inside a rain dome and notifies the entity upon entering or exiting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/raindomewatcher"},{"id":"game-scripts/components/sandstorms","title":"Sandstorms","description":"Manages global sandstorm state and calculates storm intensity based on season, weather, location, and nearby oases.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sandstorms"},{"id":"game-scripts/components/sandstormwatcher","title":"Sandstormwatcher","description":"Manages movement speed penalties during sandstorms based on vision state, mounting, and storm intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sandstormwatcher"},{"id":"game-scripts/components/sheltered","title":"Sheltered","description":"Tracks whether an entity is under cover (e.g., from trees or structures) and manages shelter state transitions, including communication and networking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sheltered"},{"id":"game-scripts/components/snowballmelting","title":"Snowballmelting","description":"Tracks ambient temperature and manages melting state transitions for entities like snowballs in response to environmental conditions and snow cover.","permalink":"/dst-api-webdocs/docs/game-scripts/components/snowballmelting"},{"id":"game-scripts/brains/tornadobrain","title":"Tornadobrain","description":"Implements decision-making logic for a tornado entity, directing it to move toward or wander near a target location.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/tornadobrain"},{"id":"game-scripts/components/wateryprotection","title":"Wateryprotection","description":"Applies protective effects (withering, cooling, extinguishing, and wetting) to entities within a radius, typically used for environmental interactions like rain or water-based abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wateryprotection"},{"id":"game-scripts/components/weather","title":"Weather","description":"Manages dynamic weather systems including precipitation, temperature, moisture, wetness, snow accumulation, lightning, and atmospheric lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/weather"},{"id":"game-scripts/components/witherable","title":"Witherable","description":"Manages cyclic withering and rejuvenation of plants based on temperature and weather conditions, and supports temporary protection periods.","permalink":"/dst-api-webdocs/docs/game-scripts/components/witherable"},{"id":"game-scripts/components/worldmeteorshower","title":"Worldmeteorshower","description":"Controls meteor loot generation logic, including conditional replacement of moon rocks with moon rock shells based on accumulated odds.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldmeteorshower"},{"id":"game-scripts/components/worldstate","title":"Worldstate","description":"Tracks and broadcasts global world state variables such as time, phase, season, weather, and moon cycles for the entire world entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldstate"}],"unlisted":false}}')}}]);